from collections import deque
import numpy as np

def solve(grid):
    grid = [row[:] for row in grid]
    H, W = len(grid), len(grid[0])

    # Find background (most common color)
    flat = [grid[r][c] for r in range(H) for c in range(W)]
    bg = max(set(flat), key=flat.count)

    # Find connected components (4-connected) of non-background cells
    visited = [[False]*W for _ in range(H)]
    components = []  # list of (color, set of (r,c))

    for r in range(H):
        for c in range(W):
            if grid[r][c] != bg and not visited[r][c]:
                color = grid[r][c]
                comp = set()
                queue = deque([(r, c)])
                visited[r][c] = True
                while queue:
                    cr, cc = queue.popleft()
                    if grid[cr][cc] == color:
                        comp.add((cr, cc))
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                            nr, nc = cr+dr, cc+dc
                            if 0 <= nr < H and 0 <= nc < W and not visited[nr][nc] and grid[nr][nc] == color:
                                visited[nr][nc] = True
                                queue.append((nr, nc))
                components.append((color, comp))

    # Separate red (2) components from others
    red_comps = [(c, s) for c, s in components if c == 2]
    other_comps = [(c, s) for c, s in components if c != 2]

    # For each non-red component, find nearest red component
    def min_dist(comp1, comp2):
        min_d = float('inf')
        for r1, c1 in comp1:
            for r2, c2 in comp2:
                d = abs(r1-r2) + abs(c1-c2)
                if d < min_d:
                    min_d = d
        return min_d

    for color, comp in other_comps:
        # Find closest red component
        best_red = None
        best_dist = float('inf')
        for _, red_set in red_comps:
            d = min_dist(comp, red_set)
            if d < best_dist:
                best_dist = d
                best_red = red_set

        if best_red is None:
            continue

        # Determine reflection type
        red_rows = set(r for r, c in best_red)
        red_cols = set(c for r, c in best_red)

        if len(best_red) == 1:
            # Point reflection
            rr, rc = list(best_red)[0]
            for r, c in comp:
                nr, nc = 2*rr - r, 2*rc - c
                if 0 <= nr < H and 0 <= nc < W and grid[nr][nc] == bg:
                    grid[nr][nc] = color
        elif len(red_cols) == 1:
            # Vertical line - reflect horizontally
            rc = list(red_cols)[0]
            for r, c in comp:
                nc = 2*rc - c
                if 0 <= nc < W and grid[r][nc] == bg:
                    grid[r][nc] = color
        elif len(red_rows) == 1:
            # Horizontal line - reflect vertically
            rr = list(red_rows)[0]
            for r, c in comp:
                nr = 2*rr - r
                if 0 <= nr < H and grid[nr][c] == bg:
                    grid[nr][c] = color

    return grid

# Test
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        for r in range(len(expected)):
            for c in range(len(expected[0])):
                if result[r][c] != expected[r][c]:
                    print(f"  ({r},{c}): got {result[r][c]}, expected {expected[r][c]}")

