        for _, red_set in red_comps:
            d = min_dist(comp, red_set)
            if d < best_dist:
                best_dist = d
                best_red = red_set

        if best_red is None:
            continue

        red_rows = set(r for r, c in best_red)
        red_cols = set(c for r, c in best_red)

        if len(best_red) == 1:
            # Point reflection
            rr, rc = list(best_red)[0]
            for r, c in comp:
                nr, nc = 2*rr - r, 2*rc - c
                if 0 <= nr < H and 0 <= nc < W and grid[nr][nc] == bg:
                    grid[nr][nc] = color
        elif len(red_cols) == 1:
            # Vertical line - reflect horizontally
            rc = list(red_cols)[0]
            for r, c in comp:
                nc = 2*rc - c
                if 0 <= nc < W and grid[r][nc] == bg:
                    grid[r][nc] = color
        elif len(red_rows) == 1:
            # Horizontal line - reflect vertically
            rr = list(red_rows)[0]
            for r, c in comp:
                nr = 2*rr - r
                if 0 <= nr < H and grid[nr][c] == bg:
                    grid[nr][c] = color

    return grid

